function findProductById(id) {
  for (const product of PRODUCTS) {
    if (product.id === id) {
      return product;
    }
  }
  return null;
}

function findProductsByCategory(category) {
  return PRODUCTS.filter((product) => product.category === category);
}

function isInStock(id) {
  const product = findProductById(id);
  return product !== null && product.stock > 0;
}

function getPriceWithTax(id) {
  const product = findProductById(id);
  if (product === null) {
    return 0;
  }
  if (product.taxFree) {
    return product.price;
  }
  return Math.round(product.price * 1.1);
}

function searchByName(keyword) {
  if (!keyword) {
    return [];
  }
  return PRODUCTS.filter((product) => product.name.includes(keyword));
}

function listCategories() {
  const seen = new Set();
  for (const product of PRODUCTS) {
    seen.add(product.category);
  }
  return Array.from(seen);
}

module.exports = {
  PRODUCTS,
  findProductById,
  findProductsByCategory,
  isInStock,
  getPriceWithTax,
  searchByName,
  listCategories,
};
